module top_module(
    input CONTROL,          
    input [4:0] IN0,        
    input [4:0] IN1,        
    output reg [4:0] input_data    
    );always@(CONTROL or IN0 or IN1) begin
        case (CONTROL)

            1'b0 : input_data <= IN0;

            1'b1 : input_data <= IN1;

            default : input_data <= 5'b00000;
        endcase
    end
endmodule
